'use strict';

function renderTable(rows, options) {
  const numCols = rows[0].length;
  const colWidths = Array(numCols).fill(0);

  for (const row of rows) {
    for (let i = 0; i < numCols; i++) {
      colWidths[i] = Math.max(colWidths[i], row[i].length);
    }
  }

  const align = options?.align || Array(numCols).fill('left');

  const renderRow = (row) => {
    const cells = [];
    for (let i = 0; i < numCols; i++) {
      const cell = row[i];
      const isLastCol = i === numCols - 1;

      if (align[i] === 'right') {
        cells.push(cell.padStart(colWidths[i]));
      } else {
        if (isLastCol) {
          cells.push(cell);
        } else {
          cells.push(cell.padEnd(colWidths[i]));
        }
      }
    }
    return cells.join(' ');
  };

  const output = [];

  if (options?.header) {
    output.push(renderRow(rows[0]));
    const separatorLength = output[0].length;
    output.push('-'.repeat(separatorLength));
    for (let i = 1; i < rows.length; i++) {
      output.push(renderRow(rows[i]));
    }
  } else {
    for (const row of rows) {
      output.push(renderRow(row));
    }
  }

  return output.join('\n');
}

function renderTableLegacy(rows) {
  return renderTable(rows);
}

module.exports = {
  renderTable,
  renderTableLegacy,
};

